sys_transform_script.script:
/** * Transform script to map and convert date fields from source to target. * * Converts source date values into GlideDateTime objects before assigning * to target fields during the transform process. * * @param {Object} source - The source record from Import Set table * @param {Object} map - The transform map configuration * @param {Object} log - Logger object for transform execution * @param {Object} target - The target record (Recruitment Request table) */ (function runTransformScript(source, map, log, target /*undefined onStart*/ ) {
// Convert source date values to GlideDateTime and assign to target fields target.u_start_date = new GlideDateTime(source.u_start_date); // Start date target.u_planned_end_date = new GlideDateTime(source.u_planned_end_date); // Planned end date target.u_actual_end_date = new GlideDateTime(source.u_actual_end_date); // Actual end date
})(source, map, log, target);
